/**
 * components/Navbar/Navbar.js
 * ============================
 * The top navigation bar, fixed at the top of every page.
 * Includes: Logo, Search bar, Cart icon, User menu
 */

import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../../context/CartContext';
import { useWishlist } from '../../context/WishlistContext';
import './Navbar.css';

export default function Navbar() {
  const [searchQuery, setSearchQuery] = useState('');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const navigate = useNavigate();
  const { cartCount } = useCart();
  const { wishlistCount } = useWishlist();
  const searchRef = useRef(null);

  // Handle search form submission
  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/products?search=${encodeURIComponent(searchQuery.trim())}`);
    }
  };

  return (
    <header className="navbar">
      <div className="navbar-container">

        {/* ── Logo ── */}
        <Link to="/" className="navbar-logo">
          <span className="logo-text">Flipkart</span>
          <span className="logo-tagline">
            <em>Explore</em>
            <img
              src="https://static-assets-web.flixcart.com/batman-returns/batman-returns/p/images/plus_icon-pu1SDe.png"
              alt="plus"
              className="logo-plus-icon"
            />
            <em>Plus</em>
          </span>
        </Link>

        {/* ── Search Bar ── */}
        <form className="search-bar" onSubmit={handleSearch}>
          <input
            ref={searchRef}
            type="text"
            placeholder="Search for products, brands and more"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="search-input"
          />
          <button type="submit" className="search-btn" aria-label="Search">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <circle cx="11" cy="11" r="8"/>
              <line x1="21" y1="21" x2="16.65" y2="16.65"/>
            </svg>
          </button>
        </form>

        {/* ── Nav Actions ── */}
        <nav className="navbar-actions">

          {/* Login Button */}
          <Link to="/login" className="nav-item">
            <span className="nav-item-label">Login</span>
          </Link>

          {/* Become a Seller */}
          <a href="#" className="nav-item hide-mobile">
            <span className="nav-item-label">Become a Seller</span>
          </a>

          {/* More dropdown (simplified) */}
          <div className="nav-item hide-mobile">
            <span className="nav-item-label">
              More
              <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor" style={{marginLeft: 2}}>
                <path d="M7 10l5 5 5-5z"/>
              </svg>
            </span>
          </div>

          {/* Wishlist */}
          <Link to="/wishlist" className="nav-item nav-item-icon">
            <div className="icon-wrapper">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
              </svg>
              {wishlistCount > 0 && <span className="badge">{wishlistCount}</span>}
            </div>
            <span className="nav-item-label">Wishlist</span>
          </Link>

          {/* Cart */}
          <Link to="/cart" className="nav-item nav-item-icon">
            <div className="icon-wrapper">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M6 2L3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4z"/>
                <line x1="3" y1="6" x2="21" y2="6"/>
                <path d="M16 10a4 4 0 01-8 0"/>
              </svg>
              {cartCount > 0 && <span className="badge">{cartCount}</span>}
            </div>
            <span className="nav-item-label">Cart</span>
          </Link>

        </nav>

        {/* ── Mobile hamburger ── */}
        <button
          className="mobile-menu-btn"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          aria-label="Menu"
        >
          <span /><span /><span />
        </button>
      </div>

      {/* ── Category Navigation Strip ── */}
      <CategoryStrip />
    </header>
  );
}

/**
 * CategoryStrip - The row of category links below the main navbar
 */
function CategoryStrip() {
  const categories = [
    { name: 'Electronics',      slug: 'electronics',   emoji: '📱' },
    { name: 'Fashion',          slug: 'fashion',        emoji: '👗' },
    { name: 'Home & Kitchen',   slug: 'home-kitchen',   emoji: '🏠' },
    { name: 'Books',            slug: 'books',          emoji: '📚' },
    { name: 'Sports',           slug: 'sports-fitness', emoji: '⚽' },
    { name: 'Toys & Games',     slug: 'toys-games',     emoji: '🎮' },
    { name: 'Beauty',           slug: 'beauty',         emoji: '💄' },
    { name: 'Grocery',          slug: 'grocery',        emoji: '🛒' },
  ];

  return (
    <div className="category-strip">
      <div className="category-strip-inner">
        {categories.map(cat => (
          <Link
            key={cat.slug}
            to={`/products?category=${cat.slug}`}
            className="category-strip-item"
          >
            <span className="cat-emoji">{cat.emoji}</span>
            <span className="cat-name">{cat.name}</span>
          </Link>
        ))}
      </div>
    </div>
  );
}
